class ETGSalesAccountStatementBatch extends RunBaseBatch
{
    CustGroupId custGroupId;
    protected static const str custGroupConvert = 'cust group';
    TransDate fromDate;
    TransDate toDate;
    DialogRunbase dialog;
    DialogField custGroupField;
    DialogField fromDateField;
    DialogField toDateField;

    #define.CurrentVersion(1)
    #LOCALMACRO.CurrentList
    custGroupId
    #ENDMACRO

}

Method.Source:
public static void main(Args args)
{
    ETGSalesAccountStatementBatch accountStatementBatch = new ETGSalesAccountStatementBatch();
    if(accountStatementBatch.prompt())
    {
        accountStatementBatch.runOperation();
    }

}

public void run()
{
    CustTable                    custTable;
    SrsReportRunService          reportRunService;
    SRSPrintDestinationSettings  printDestinationSettings;
    ETG_SalesAccountStatementContract rdpContract;
    ETGSalesAccountStController1 controller;
    ETGSalesAccountStContract    reportDataContract;
    System.IO.MemoryStream       stream;
    str                          fileName, downloadUrl;

    while select custTable
        where custTable.CustGroup == custGroupId
    {
        // Initialize the report contract
        rdpContract = new ETG_SalesAccountStatementContract();

        //  Set required report parameters
        rdpContract.parmFromDate(fromDate);
        rdpContract.parmToDate(toDate);
        rdpContract.parmCustomerAccount(custTable.AccountNum);
        // If your RDP also has a parmCompany or similar, set it here too

        // Initialize controller
        controller = new ETGSalesAccountStController1();
        controller.parmReportName(ssrsReportStr(ETG_SalesAccountStatement, PrecisionDesign2));
        controller.parmReportContract().parmRdpContract(rdpContract);

        // Define print settings
        fileName = strFmt("SalesStatement_%1.xlsx", custTable.AccountNum);
        printDestinationSettings = new SRSPrintDestinationSettings();
        printDestinationSettings.fileFormat(SRSReportFileFormat::Excel);
        printDestinationSettings.parmFileName(fileName);
        printDestinationSettings.printMediumType(SRSPrintMediumType::File);

        // Prepare the report data contract
        reportDataContract = new ETGSalesAccountStContract();
        reportDataContract.unpack(controller.parmReportContract().pack());
        reportDataContract.parmReportExecutionInfo(new SRSReportExecutionInfo());
        reportDataContract.parmPrintSettings(printDestinationSettings);

        // Run the report
        reportRunService = new SrsReportRunService();
        reportRunService.runReport(reportDataContract);

        // Convert report to stream
        stream = new System.IO.MemoryStream(reportDataContract.parmReportBytes());

        // Send to temporary storage for download
        downloadUrl = File::SendFileToTempStore(
            stream,
            printDestinationSettings.parmFileName(),
            classStr(FileUploadTemporaryStorageStrategy),
            true);

        // Open PDF in browser (new tab)
        new Browser().navigate(downloadUrl, true, false);
    }

    info("Report generation completed for all customers in group " + custGroupId);
}

public static ClassDescription description()
{
    return "Customer account statement";
}

public boolean unpack(container packedClass)
{
    Integer version = conPeek(packedClass,1);
    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = packedClass;
            break;
        default:
            return false;
    }
    return true;
}

public void putToDialog()
{
    super();
    custGroupField.value(custGroupId);
    fromDateField.value(fromDate);
    toDateField.value(toDate);
}

public boolean getFromDialog()
{
    custGroupId = custGroupField.value();
    fromDate = fromDateField.value();
    toDate = toDateField.value();

    return super();
}

public Object dialog()
{
    dialog = super();
    custGroupField = dialog.addFieldValue(IdentifierStr(CustGroupId), custGroupId, "Customer group");
    fromDateField = dialog.addFieldValue(identifierStr(TransDate), fromDate, "From date");
    toDateField = dialog.addFieldValue(identifierStr(TransDate), toDate, "To date");

    return dialog;
}

public CustGroupId parmCustGroup(CustGroupId _custGroupId = custGroupId)
{
    custGroupId = _custGroupId;
    return custGroupId;
}

public TransDate parmFromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

public TransDate parmToDate(TransDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}
